// export default DatasetPage;

const DatasetPage = () => {

    const sections = [
        {
            title: 'Self-Instruct Generated Dataset',
            datasets: [
                {
                    title:'BGP Knowledge',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'PyBGPStream Base',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'PyBGPStream Real-time Stream',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
            ],

            title: 'Manual Seed Tasks',
            datasets: [
                {
                    title:'BGP Knowledge I',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'BGP Knowledge II',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'PyBGPStream Base',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'PyBGPStream Real Cases',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },
                {
                    title:'PyBGPStream Real-time Stream',
                    imageUrl: '',
                    fileCount: 1111,
                    size: '10 MB',
                    fileType: 'json'

                },             
            ]

        }
    ];

    return (
        <div>
            {sections.map((section) => (
                <React.Fragment key={section.title}>
                    <Typography variant='h6' gutterBottom>
                        {section.title}
                    </Typography>
                    <Grid container spacing={2}>
                        {section.datasets.map((dataset, index) => (
                            <Grid item xs={12} sm={6} md={3} key={index}>
                               <Card>
                                <CardMedia
                                component='img'
                                height='140'
                                image={dataset.imageUrl}
                                alt={dataset.title}/>
                                <CardContent>

                                </CardContent>
                                </Card> 
                            </Grid>
                        ))}
                    </Grid>
                </React.Fragment>
            ))}
        </div>
    );
}

export default DatasetPage;
